verify-artifacts-flow.script:
test -f out/prepare.txt || {
  echo '[ERROR] missing out/prepare.txt'
  exit 1
}
test -f out/linux.txt || {
  echo '[ERROR] missing out/linux.txt'
  exit 1
}
test -f out/macos.txt || {
  echo '[ERROR] missing out/macos.txt'
  exit 1
}
test -f out/release.txt || {
  echo '[ERROR] missing out/release.txt'
  exit 1
}
grep -F 'prepare stage artifact' out/prepare.txt || {
  echo '[ERROR] prepare artifact mismatch'
  exit 1
}
grep -F 'linux build artifact' out/linux.txt || {
  echo '[ERROR] linux artifact mismatch'
  exit 1
}
grep -F 'macos build artifact' out/macos.txt || {
  echo '[ERROR] macos artifact mismatch'
  exit 1
}
grep -F 'release bundle' out/release.txt || {
  echo '[ERROR] release artifact mismatch'
  exit 1
}
